SELECT experiment_name
FROM experiments
ORDER BY experiment_id DESC;

SELECT experiment_id, deployment_date, version, deployed_by
FROM deployment
WHERE environment = 'production';

SELECT category, COUNT(lab_name) as lab_count
FROM labs
GROUP BY category;

SELECT experiment_id, COUNT(deployment_id) AS deployment_count
FROM deployment
GROUP BY experiment_id;

SELECT dev_name
FROM dev_team
WHERE dev_id = 0;
